<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Playground</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 16px;
    padding: 20px;
  }
  h1 { font-size: 1.4rem; color: #aaa; letter-spacing: 0.05em; }
  #controls {
    display: flex;
    gap: 12px;
  }
  button {
    background: #1e1e2e;
    color: #cdd6f4;
    border: 1px solid #313244;
    border-radius: 8px;
    padding: 8px 20px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
  }
  button:hover { background: #313244; border-color: #585b70; }
  button:active { background: #45475a; }
  #sim {
    border: 2px solid #313244;
    border-radius: 8px;
    cursor: crosshair;
    display: block;
    box-shadow: 0 0 40px rgba(0,0,0,0.6);
  }
</style>
</head>
<body>
<h1>Bouncing Ball Playground</h1>
<div id="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>
<canvas id="sim" width="600" height="500"></canvas>
<script>
(function() {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.4;
  const RESTITUTION = 0.78;
  const DEFAULT_RADIUS = 18;

  let balls = [];
  let running = true;
  let animId = null;

  const COLORS = [
    '#f38ba8','#fab387','#f9e2af','#a6e3a1',
    '#89dceb','#89b4fa','#cba6f7','#f5c2e7',
    '#74c7ec','#94e2d5',
  ];
  let colorIndex = 0;

  function randomVx() { return (Math.random() - 0.5) * 6; }
  function randomVy() { return -Math.random() * 4 - 2; }

  function addBall(x, y, vx, vy, r) {
    if (vx === undefined) vx = randomVx();
    if (vy === undefined) vy = randomVy();
    if (r === undefined || r === null) r = DEFAULT_RADIUS;
    r = Math.max(2, r);
    // Clamp initial position inside canvas
    x = Math.max(r, Math.min(W - r, x));
    y = Math.max(r, Math.min(H - r, y));
    balls.push({
      x, y, vx, vy, r,
      color: COLORS[colorIndex % COLORS.length],
    });
    colorIndex++;
  }

  function clear() {
    balls = [];
  }

  function step(dt) {
    if (dt === undefined) dt = 1;
    for (const b of balls) {
      b.vy += GRAVITY * dt;
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // Floor
      if (b.y + b.r >= H) {
        b.y = H - b.r;
        b.vy = -Math.abs(b.vy) * RESTITUTION;
      }
      // Ceiling
      if (b.y - b.r <= 0) {
        b.y = b.r;
        b.vy = Math.abs(b.vy) * RESTITUTION;
      }
      // Right wall
      if (b.x + b.r >= W) {
        b.x = W - b.r;
        b.vx = -Math.abs(b.vx) * RESTITUTION;
      }
      // Left wall
      if (b.x - b.r <= 0) {
        b.x = b.r;
        b.vx = Math.abs(b.vx) * RESTITUTION;
      }
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);
    ctx.fillStyle = '#11111b';
    ctx.fillRect(0, 0, W, H);

    for (const b of balls) {
      // Shadow glow
      ctx.save();
      ctx.shadowColor = b.color;
      ctx.shadowBlur = 12;

      // Ball gradient
      const grad = ctx.createRadialGradient(
        b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,
        b.x, b.y, b.r
      );
      grad.addColorStop(0, '#ffffff55');
      grad.addColorStop(0.3, b.color);
      grad.addColorStop(1, b.color + '88');

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
      ctx.restore();
    }

    // Ball count
    ctx.fillStyle = '#585b70';
    ctx.font = '13px system-ui';
    ctx.fillText(`${balls.length} ball${balls.length !== 1 ? 's' : ''}`, 10, H - 10);
  }

  function loop() {
    if (running) step(1);
    animId = requestAnimationFrame(loop);
  }

  // Controls
  document.getElementById('drop').addEventListener('click', () => {
    addBall(W / 2 + (Math.random() - 0.5) * 100, 40);
  });

  document.getElementById('play').addEventListener('click', function() {
    running = !running;
    this.textContent = running ? 'Pause' : 'Play';
  });

  document.getElementById('clear').addEventListener('click', () => {
    clear();
    draw();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y);
  });

  // Expose API
  window.sim = {
    get w() { return W; },
    get h() { return H; },
    balls() {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall,
    clear,
    step,
  };

  // Kick off
  draw();
  animId = requestAnimationFrame(loop);
})();
</script>
</body>
</html>
